// ── CONFIG ────────────────────────────────────────────────
var ADMIN_PATH='admin-panel-qnaxia-2026-super-secret-login';
var API='/api';
var SITE='Qnaxia';
// ── AUTH (JWT — no password in frontend) ─────────────────
var auth=sessionStorage.getItem('admin-auth')==='1';
var TOKEN=sessionStorage.getItem('admin-token')||'';
function authHdr(){return{'Authorization':'Bearer '+TOKEN,'Content-Type':'application/json'};}
function doLogout(){sessionStorage.removeItem('admin-auth');sessionStorage.removeItem('admin-token');auth=false;TOKEN='';toast('Logged out successfully! 👋','ok');go('/');}
// ── HELPERS ───────────────────────────────────────────────
var app=document.getElementById('app');
function ge(id){return document.getElementById(id);}
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function slugify(s){return s.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'')||('p'+Date.now());}
function readTime(t){return Math.max(1,Math.round((String(t||'').trim().split(/\s+/).length)/200))+' min read';}
function fmtDate(d){return d?new Date(d).toLocaleDateString('en-US',{year:'numeric',month:'short',day:'numeric'}):''}
function fmtLong(d){return d?new Date(d).toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'}):''}
// ── TOAST ─────────────────────────────────────────────────
function toast(msg,type){var box=ge('toast-box'),el=document.createElement('div');el.className='t-item '+(type||'ok');el.textContent=msg;box.appendChild(el);setTimeout(function(){el.classList.add('show');},10);setTimeout(function(){el.classList.remove('show');setTimeout(function(){if(el.parentNode)box.removeChild(el);},300);},3200);}
// ── COOKIE ────────────────────────────────────────────────
function initCk(){if(!sessionStorage.getItem('ck'))ge('ck').style.display='flex';}
function setCk(v){sessionStorage.setItem('ck',v?'1':'0');ge('ck').style.display='none';}
// ── THEME TOGGLE ─────────────────────────────────────────
var isDark=localStorage.getItem('theme')==='dark';
function toggleTheme(){isDark=!isDark;document.documentElement.setAttribute('data-theme',isDark?'dark':'light');localStorage.setItem('theme',isDark?'dark':'light');document.getElementById('theme-toggle').textContent=isDark?'☀️':'🌙';}
function initTheme(){isDark=localStorage.getItem('theme')==='dark';if(isDark){document.documentElement.setAttribute('data-theme','dark');document.getElementById('theme-toggle').textContent='☀️';}}
// ── Q&A PARSER ───────────────────────────────────────────
function parseQA(content){if(!content)return[];var lines=content.split('\n').map(function(l){return l.trim();}).filter(function(l){return l;});var pairs=[];var hasQPrefix=lines.some(function(l){return/^[Qq]\d*[\.\:\)]\s/.test(l);});if(hasQPrefix){var cur=null;lines.forEach(function(line){var qm=line.match(/^[Qq]\d*[\.\:\)]\s*(.+)/);var am=line.match(/^[Aa]\d*[\.\:\)]\s*(.+)/);if(qm){cur={q:qm[1].trim(),a:''};pairs.push(cur);}else if(am&&cur){cur.a=am[1].trim();}});if(pairs.filter(function(p){return p.a;}).length>0)return pairs;}var numReg=/^(\d+)[\.\)]\s+(.+)/;var hasNum=lines.some(function(l){return numReg.test(l);});if(hasNum){var i=0;while(i<lines.length){var qm=lines[i].match(numReg);if(qm&&i+1<lines.length){var ans=[],j=i+1;while(j<lines.length&&!numReg.test(lines[j])){ans.push(lines[j]);j++;}if(ans.length>0)pairs.push({q:qm[2].trim(),a:ans.join(' ').trim()});i=j;}else{i++;}}if(pairs.length>0)return pairs;}return[];}
function renderQAHtml(pairs){if(!pairs||!pairs.length)return'';var html='<div class="qa-count">📚 '+pairs.length+' Questions &amp; Answers</div><div class="qa-list">';pairs.forEach(function(qa,i){html+='<div class="qa-item">'+'<div class="qa-q"><span class="qa-num">Q'+(i+1)+'</span><span class="qa-q-text">'+esc(qa.q)+'</span></div>'+'<div class="qa-a"><div class="qa-a-dot"></div><span class="qa-a-text">'+esc(qa.a)+'</span></div>'+'</div>';});return html+'</div>';}
function renderContent(content){var pairs=parseQA(content);if(pairs.length>=2){var firstQ=content.search(/(\d+[\.\)]\s|[Qq]\d*[\.\:\)]\s)/);var intro=firstQ>0?content.slice(0,firstQ).trim():'';return(intro?'<p class="qa-intro">'+esc(intro)+'</p>':'')+renderQAHtml(pairs);}return'<div class="post-content">'+esc(content)+'</div>';}
// ── NAVBAR ────────────────────────────────────────────────
function updateNav(path){var nav=ge('nav'),logo=ge('logo');if(!nav)return;var onHero=(path==='/'||path==='');if(onHero){var sc=window.scrollY>70;nav.classList.toggle('solid',sc);nav.style.color=sc?'#1F2937':'#1F2937';if(logo)logo.style.color=sc?'#0D9488':'#0D9488';}else{nav.classList.add('solid');nav.style.color='#1F2937';if(logo)logo.style.color='#0D9488';}}window.addEventListener('scroll',function(){updateNav(getPath());});
// ── API helpers ───────────────────────────────────────────
function normalizePost(r){return{slug:r.slug||'',title:r.title||'',content:r.content||'',excerpt:r.excerpt||'',author:r.author||'Editor',tags:r.tags||'',coverUrl:r.cover_url||'',status:r.status||'draft',scheduleTime:r.schedule_time||'',publishedAt:r.published_at||'',createdAt:r.created_at||'',updatedAt:r.updated_at||'',qaPairs:r.qa_pairs||[]};}
async function apiGet(path){var hdrs=auth?{'Authorization':'Bearer '+TOKEN}:{};var res=await fetch(API+path,{headers:hdrs});if(!res.ok)return null;var ct=res.headers.get('content-type')||'';if(!ct.includes('json'))return null;return res.json();}
async function loadPosts(){try{var url=auth?'/admin/posts':'/posts';var data=await apiGet(url);if(!data||!Array.isArray(data))return[];return data.map(normalizePost);}catch(e){console.error('loadPosts:',e);return[];}}
async function fetchPost(slug){try{var data=await apiGet('/posts/'+encodeURIComponent(slug));return data?normalizePost(data):null;}catch(e){console.error('fetchPost:',e);return null;}}
// ── ROUTER ────────────────────────────────────────────────
function go(path){history.pushState(null,'',path);route();}
function getPath(){return window.location.pathname;}
function route(){var path=getPath();window.scrollTo(0,0);updateNav(path);if(path==='/'||path===''){renderHome();return;}if(path==='/'+ADMIN_PATH){renderLogin();return;}if(path==='/'+ADMIN_PATH+'/dash'){renderDash();return;}if(path==='/'+ADMIN_PATH+'/new'){renderEditor('');return;}if(path.indexOf('/'+ADMIN_PATH+'/edit/')===0){renderEditor(path.slice(ADMIN_PATH.length+7));return;}if(path.indexOf('/post/')===0){renderPost(path.slice(6));return;}renderHome();}
window.addEventListener('popstate',route);
document.addEventListener('DOMContentLoaded',route);
// ── HOME ──────────────────────────────────────────────────
async function renderHome(){app.innerHTML='<div style="padding-top:72px"><div class="hero">'+'<div class="hero-content">'+'<div class="hero-pill">✦ New Stories Every Week</div>'+'<h1>Discover Stories<br>That Matter</h1>'+'<p>Ideas, insights and in-depth articles from writers who care about quality.</p>'+'</div></div><div style="text-align:center;padding:80px 20px;color:#9CA3AF">'+'<div style="font-size:32px;margin-bottom:14px">📖</div>Loading stories...</div></div>';var posts=await loadPosts();if(!posts||posts.length===0){app.innerHTML='<div style="padding-top:72px"><div class="hero">'+'<div class="hero-content">'+'<div class="hero-pill">✦ New Stories Every Week</div>'+'<h1>Discover Stories<br>That Matter</h1>'+'<p>Ideas, insights and in-depth articles from writers who care about quality.</p>'+'</div></div>'+'<div style="text-align:center;padding:80px 20px;color:#9CA3AF"><p style="font-size:40px;margin-bottom:12px">✍️</p><p>No stories published yet.</p></div>'+'<footer><strong>'+SITE+'</strong>© '+new Date().getFullYear()+' '+SITE+'. All rights reserved.</footer></div>';return;}var pub=posts.filter(function(p){return p.status==='published';}).sort(function(a,b){return new Date(b.publishedAt)-new Date(a.publishedAt);});var top=pub[0]||null,rest=pub.slice(1);var featHtml='';if(top){var ftag=top.tags?top.tags.split(',')[0].trim():'Featured';featHtml='<div class="featured-wrap">'+'<a href="/post/'+top.slug+'" class="featured-card">'+'<div class="feat-img">'+ (top.coverUrl?'<img src="'+esc(top.coverUrl)+'" onerror="this.style.display=\'none\'">':'')+'<div class="feat-img-overlay"></div>'+'<span class="feat-badge">'+esc(ftag)+'</span>'+'</div>'+'<div class="feat-body">'+'<div class="feat-label">✦ Featured Story</div>'+'<h2 class="feat-title">'+esc(top.title)+'</h2>'+'<p class="feat-excerpt">'+esc(top.excerpt||top.content.slice(0,130))+'…</p>'+'<div class="feat-meta">'+'<span>'+esc(top.author)+'</span><span class="meta-dot"></span>'+'<span>'+fmtDate(top.publishedAt)+'</span><span class="meta-dot"></span>'+'<span>'+readTime(top.content)+'</span>'+'</div>'+'<div style="margin-top:20px"><span class="btn btn-p" style="font-size:13px;padding:9px 20px">Read Story →</span></div>'+'</div>'+'</a></div>';}var cards='';rest.forEach(function(p){var tag=p.tags?p.tags.split(',')[0].trim():'';cards+='<a href="/post/'+p.slug+'" class="pcard">'+'<div class="pcard-img">'+(p.coverUrl?'<img src="'+esc(p.coverUrl)+'" onerror="this.style.display=\'none\'">':'')+'</div>'+'<div class="pcard-body">'+(tag?'<div class="pcard-tag">'+esc(tag)+'</div>':'')+'<h3 class="pcard-title">'+esc(p.title)+'</h3>'+'<p class="pcard-excerpt">'+esc(p.excerpt||p.content.slice(0,100))+'…</p>'+'<div class="pcard-meta"><span>'+fmtDate(p.publishedAt)+'</span><span class="meta-dot"></span><span>'+readTime(p.content)+'</span></div>'+'</div></a>';});app.innerHTML='<div style="padding-top:72px"><div class="hero">'+'<div class="hero-content">'+'<div class="hero-pill">✦ New Stories Every Week</div>'+'<h1>Discover Stories<br>That Matter</h1>'+'<p>Ideas, insights and in-depth articles from writers who care about quality.</p>'+'</div></div>'+featHtml+'<div class="section" style="'+(top?'padding-top:84px':'')+'">'+ (rest.length?'<div class="sec-head"><h2 class="sec-title">More Stories</h2></div><div class="grid">'+cards+'</div>':'')+'</div>'+'<footer><strong>'+SITE+'</strong>© '+new Date().getFullYear()+' '+SITE+'. All rights reserved.</footer></div>';}
// ── SINGLE POST ───────────────────────────────────────────
async function renderPost(slug){app.innerHTML='<div style="padding-top:72px;text-align:center;padding:180px 20px;color:#94A3B8">'+'<div style="font-size:40px;margin-bottom:16px">⏳</div>Loading...</div>';var p=await fetchPost(slug);if(!p){app.innerHTML='<div style="padding-top:72px;text-align:center;padding:180px 20px">'+'<p style="font-size:64px;margin-bottom:18px">🔍</p>'+'<h2 style="font-size:28px;font-weight:800;margin-bottom:12px;color:#fff">Post Not Found</h2>'+'<p style="color:#94A3B8;margin-bottom:32px">This story may have been moved or deleted.</p>'+'<a href="/" class="btn btn-p">← Back to Home</a></div>';return;}var tags='';if(p.tags)p.tags.split(',').forEach(function(t){tags+='<span class="ph-tag">'+esc(t.trim())+'</span>';});var pairs=parseQA(p.content);if(pairs.length){var old=document.getElementById('faq-schema');if(old)old.remove();var sc=document.createElement('script');sc.id='faq-schema';sc.type='application/ld+json';sc.textContent=JSON.stringify({'@context':'https://schema.org','@type':'FAQPage',mainEntity:pairs.map(function(qa){return{'@type':'Question','name':qa.q,'acceptedAnswer':{'@type':'Answer','text':qa.a}};})});document.head.appendChild(sc);}document.title=p.title+' — '+SITE;var metaTags=[['og:title',p.title],['og:description',p.excerpt||p.content.slice(0,160)],['og:image',p.coverUrl||''],['og:url','https://qnaxia.com/#/post/'+p.slug],['og:type','article']];metaTags.forEach(function(m){var el=document.querySelector('meta[property="'+m[0]+'"]');if(!el){el=document.createElement('meta');el.setAttribute('property',m[0]);document.head.appendChild(el);}el.setAttribute('content',m[1]);});var coverHtml=p.coverUrl?'<div style="max-width:1000px;margin:0 auto 48px;border-radius:20px;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.4)">'+'<img src="'+esc(p.coverUrl)+'" style="width:100%;max-height:450px;object-fit:cover;display:block" onerror="this.style.display=\'none\'"></div>':'';app.innerHTML='<div style="padding-top:64px">'+'<div class="ph">'+'<div class="ph-content">'+coverHtml+(tags?'<div class="ph-tags">'+tags+'</div>':'')+'<h1>'+esc(p.title)+'</h1>'+'<div class="ph-meta">'+'<span class="author">✍️ '+esc(p.author)+'</span>'+'<span>•</span>'+'<span>'+fmtLong(p.publishedAt)+'</span>'+'<span>•</span>'+'<span>'+readTime(p.content)+'</span>'+'</div>'+'</div>'+'</div>'+'<div class="post-body">'+renderContent(p.content)+'<div style="margin-top:48px;padding-top:32px;border-top:1px solid #E5E7EB;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:16px">'+'<a href="/" style="color:#0D9488;font-size:15px;font-weight:600;display:flex;align-items:center;gap:8px">← All Stories</a>'+'<div style="display:flex;gap:16px;font-size:13px;color:#9CA3AF">'+'<span>'+fmtLong(p.publishedAt)+'</span>'+'<span>•</span>'+'<span>'+readTime(p.content)+'</span>'+'</div>'+'</div>'+'</div>'+'<footer><strong>'+SITE+'</strong>© '+new Date().getFullYear()+' '+SITE+'. All rights reserved.</footer></div>';}
// ── ADMIN LOGIN ───────────────────────────────────────────
function renderLogin(){if(auth){go('/'+ADMIN_PATH+'/dash');return;}document.title='Admin — '+SITE;app.innerHTML='<div style="padding-top:64px"><div class="login-wrap"><div class="login-card">'+'<div style="text-align:center;margin-bottom:32px">'+'<div class="login-icon">🔐</div>'+'<h2 style="font-size:22px;font-weight:900;color:#1F2937">Admin Access</h2>'+'<p style="font-size:13px;color:#9CA3AF;margin-top:6px">'+SITE+' Content Management</p></div>'+'<div class="fg"><label class="flabel">Password</label>'+'<input id="pw" type="password" class="finput" placeholder="Enter admin password" autocomplete="current-password"></div>'+'<div id="lerr" style="display:none;color:#ef4444;font-size:13px;padding:10px 14px;background:#fef2f2;border-radius:7px;border:1px solid #fecaca;margin-bottom:14px">❌ Incorrect password.</div>'+'<button onclick="doLogin()" class="btn btn-p" style="width:100%;justify-content:center;padding:13px;font-size:15px">Sign In</button>'+'<p style="text-align:center;margin-top:20px"><a href="/" style="color:#9ca3bf;font-size:13px">← Return to blog</a></p>'+'</div></div></div>';setTimeout(function(){var el=ge('pw');if(!el)return;el.focus();el.onkeydown=function(e){if(e.key==='Enter')doLogin();};},30);}
async function doLogin(){var pw=ge('pw');if(!pw)return;var err=ge('lerr');if(err)err.style.display='none';try{var res=await fetch(API+'/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({password:pw.value})});if(!res.ok){if(err)err.style.display='block';pw.value='';pw.focus();return;}var data=await res.json();if(!data.token){if(err)err.style.display='block';return;}TOKEN=data.token;sessionStorage.setItem('admin-auth','1');sessionStorage.setItem('admin-token',TOKEN);auth=true;toast('Logged in successfully! 👋','ok');go('/'+ADMIN_PATH+'/dash');}catch(e){if(err)err.style.display='block';pw.value='';pw.focus();}}
// ── DASHBOARD ─────────────────────────────────────────────
async function renderDash(){if(!auth){toast('Please login first','err');go('/'+ADMIN_PATH);return;}document.title='Dashboard — '+SITE;app.innerHTML='<div style="padding-top:64px;text-align:center;padding:100px;color:#9ca3af">Loading...</div>';var posts=await loadPosts();var sorted=posts.slice().sort(function(a,b){return new Date(b.createdAt)-new Date(a.createdAt);});var cnt=function(s){return posts.filter(function(p){return p.status===s;}).length;};var stats=[{l:'Total',n:posts.length,c:'#0D9488'},{l:'Published',n:cnt('published'),c:'#10B981'},{l:'Drafts',n:cnt('draft'),c:'#6B7280'},{l:'Scheduled',n:cnt('scheduled'),c:'#F59E0B'}];var sc='';stats.forEach(function(s){sc+='<div class="stat" style="border-left-color:'+s.c+'"><div style="font-size:28px;font-weight:900;color:'+s.c+'">'+s.n+'</div><div style="font-size:13px;color:#6B7280;margin-top:3px">'+s.l+'</div></div>';});var rows='';if(sorted.length){sorted.forEach(function(p){var bc=p.status==='published'?'b-pub':p.status==='draft'?'b-draft':'b-sched';var sn=p.status==='scheduled'&&p.scheduleTime?'<span style="font-size:11px;color:#f59e0b;margin-left:8px">🕐 '+new Date(p.scheduleTime).toLocaleString()+'</span>':'';rows+='<div class="tbl-row">'+'<div style="flex:1;min-width:0">'+'<div style="font-weight:700;font-size:14px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:380px">'+esc(p.title)+'</div>'+'<div style="font-size:11px;color:#9ca3af;margin-top:3px">'+fmtDate(p.createdAt)+sn+'</div></div>'+'<span class="badge '+bc+'">'+p.status+'</span>'+'<a href="/'+ADMIN_PATH+'/edit/'+p.slug+'" class="btn btn-g" style="padding:6px 14px;font-size:12px">Edit</a>'+'<button onclick="delPost(\''+p.slug+'\')" class="btn btn-d" style="padding:6px 14px;font-size:12px">Delete</button>'+'</div>';});}else{rows='<div style="text-align:center;padding:60px;color:#9CA3AF"><p style="font-size:32px;margin-bottom:12px">✍️</p><p>No posts yet. <span onclick="go(\'/'+ADMIN_PATH+'/new\')" style="color:#0D9488;font-weight:700;cursor:pointer">Create your first post →</span></p></div>';}app.innerHTML='<div style="background:linear-gradient(135deg,#F0FDFA,#F5FFFA);min-height:100vh;padding-top:72px">'+'<div class="adm-wrap">'+'<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:28px;flex-wrap:wrap;gap:12px">'+'<div><h1 style="font-size:24px;font-weight:900;color:#1F2937">Dashboard</h1><p style="font-size:13px;color:#9CA3AF;margin-top:3px">Manage your content</p></div>'+'<div style="display:flex;gap:10px;align-items:center;flex-wrap:wrap">'+'<a href="/" style="font-size:13px;color:#6B7280">View Blog ↗</a>'+'<span onclick="go(\'/'+ADMIN_PATH+'/new\')" class="btn btn-p" style="cursor:pointer">+ New Post</span>'+'<button onclick="doLogout()" class="btn btn-g" style="padding:9px 16px;font-size:13px">Logout</button>'+'</div></div>'+'<div class="stat-grid">'+sc+'</div>'+'<div class="tbl"><div class="tbl-head">All Posts</div>'+rows+'</div>'+'</div></div>';}
async function delPost(slug){if(!confirm('Delete this post permanently?'))return;try{var res=await fetch(API+'/admin/posts/'+slug,{method:'DELETE',headers:{'Authorization':'Bearer '+TOKEN}});if(res.ok){toast('Post deleted! 🗑️','ok');renderDash();}else{toast('Delete failed: '+res.status,'err');}}catch(e){toast('Delete error: '+e.message,'err');}}
// ── EDITOR ────────────────────────────────────────────────
function mkF(label,id,type,val,ph){return'<div class="fg"><label class="flabel" for="'+id+'">'+label+'</label>'+'<input id="'+id+'" type="'+type+'" class="finput" value="'+esc(val)+'" placeholder="'+esc(ph)+'"></div>';}
async function renderEditor(slug){if(!auth){toast('Please login first','err');go('/'+ADMIN_PATH);return;}document.title=(slug?'Edit':'New Post')+' — '+SITE;app.innerHTML='<div style="padding-top:64px;text-align:center;padding:100px;color:#9ca3af">Loading...</div>';var posts=await loadPosts();var p=slug?posts.find(function(x){return x.slug===slug;}):null;var v=function(f){return p?(p[f]||''):''};var isSched=v('status')==='scheduled';var sv=v('scheduleTime')?v('scheduleTime').slice(0,16):'';app.innerHTML='<div style="background:linear-gradient(135deg,#F0FDFA,#F5FFFA);min-height:100vh;padding-top:72px">'+'<div class="ed-wrap">'+'<div style="display:flex;align-items:center;gap:12px;margin-bottom:24px">'+'<span onclick="go(\'/'+ADMIN_PATH+'/dash\')" style="width:38px;height:38px;background:#fff;border:1.5px solid #E5E7EB;border-radius:9px;display:inline-flex;align-items:center;justify-content:center;color:#6B7280;font-size:18px;flex-shrink:0;cursor:pointer">←</span>'+'<div><h1 style="font-size:20px;font-weight:900;color:#1F2937">'+(p?'Edit Post':'New Post')+'</h1>'+(p?'<p style="font-size:12px;color:#9CA3AF;margin-top:2px">Updated: '+fmtDate(p.updatedAt)+'</p>':'')+'</div></div>'+'<div class="ed-card">'+mkF('Title *','e-title','text',v('title'),'e.g. 50 Psychology Questions and Answers')+mkF('Cover Image URL','e-cover','url',v('coverUrl'),'https://example.com/cover.jpg')+'<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">'+mkF('Author','e-author','text',v('author'),'Your name')+mkF('Tags','e-tags','text',v('tags'),'Psychology, Q&A, Education')+'</div>'+mkF('Excerpt','e-excerpt','text',v('excerpt'),'Brief summary shown on homepage...')+'<div class="fg"><label class="flabel" for="e-content">Content * (Q&amp;A format)</label>'+'<div style="background:#F0FDFA;border:1px solid #CCFBF1;border-radius:8px;padding:12px 14px;margin-bottom:10px;font-size:12px;color:#0F766E;line-height:1.7">'+'✅ <strong>Format:</strong> 1. Question?<br>Answer here.<br><br>2. Next question?<br>Next answer.'+'</div>'+'<textarea id="e-content" class="finput" rows="16" placeholder="1. Question here?\nAnswer here.\n\n2. Next question?\nNext answer." style="resize:vertical;min-height:260px;line-height:1.7;font-size:13px;font-family:monospace">'+esc(v('content'))+'</textarea></div>'+'<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;align-items:start">'+'<div class="fg"><label class="flabel">Status</label>'+'<select id="e-status" class="finput" onchange="tglSched()">'+'<option value="published"'+(v('status')==='published'?' selected':'')+'>✅ Published</option>'+'<option value="draft"'+(v('status')==='draft'?' selected':'')+'>📝 Draft</option>'+'<option value="scheduled"'+(v('status')==='scheduled'?' selected':'')+'>🕐 Scheduled</option>'+'</select></div>'+'<div id="sb" style="display:'+(isSched?'block':'none')+'">'+'<div class="fg"><label class="flabel">Publish Date &amp; Time</label>'+'<input type="datetime-local" id="e-sched" class="finput" value="'+sv+'"></div>'+'</div>'+'</div>'+'<div id="ed-err" style="display:none;color:#ef4444;font-size:13px;padding:10px 14px;background:#fef2f2;border-radius:7px;border:1px solid #fecaca;margin-bottom:16px"></div>'+'<div style="display:flex;gap:12px;align-items:center">'+'<button onclick="savePost(\''+esc(slug||'')+'\');" class="btn btn-p" style="padding:12px 32px;font-size:15px">💾 Save Post</button>'+'<span onclick="go(\'/'+ADMIN_PATH+'/dash\')" class="btn btn-g" style="cursor:pointer">Cancel</span>'+'</div>'+'</div></div></div>';}
function tglSched(){var b=ge('sb');if(b)b.style.display=ge('e-status').value==='scheduled'?'block':'none';}
function showErr(m){var e=ge('ed-err');if(e){e.textContent='⚠️ '+m;e.style.display='block';}}
async function savePost(existSlug){var ee=ge('ed-err');if(ee)ee.style.display='none';var title=(ge('e-title').value||'').trim();var content=(ge('e-content').value||'').trim();var status=ge('e-status').value;var schedEl=ge('e-sched'),sched=schedEl?schedEl.value:'';if(!title){showErr('Title is required.');return;}if(!content){showErr('Content is required.');return;}if(status==='scheduled'&&!sched){showErr('Please pick a publish date & time.');return;}var payload={slug:existSlug||slugify(title),title:title,content:content,status:status,schedule_time:status==='scheduled'?sched:null,cover_url:(ge('e-cover').value||'').trim(),author:(ge('e-author').value||'').trim(),tags:(ge('e-tags').value||'').trim(),excerpt:(ge('e-excerpt').value||'').trim(),qa_pairs:[]};try{var method=existSlug?'PUT':'POST';var url=existSlug?(API+'/admin/posts/'+existSlug):(API+'/admin/posts');var res=await fetch(url,{method:method,headers:authHdr(),body:JSON.stringify(payload)});if(!res.ok){var err=await res.json();throw new Error(err.error||'Save failed ('+res.status+')');}toast('Post saved! 🎉','ok');go('/'+ADMIN_PATH+'/dash');}catch(e){showErr(e.message);}}
// ── INIT ──────────────────────────────────────────────────
initTheme();
initCk();
route();